import { jest } from '@jest/globals';
import CodebaseIndexer from '../src/indexer/CodebaseIndexer.js';

describe('CodebaseIndexer', () => {
  let indexer;
  let mockFileSystemManager;

  beforeEach(() => {
    // Create mock FileSystemManager
    mockFileSystemManager = {
      loadGitignore: jest.fn().mockResolvedValue(undefined),
      isBinary: jest.fn().mockResolvedValue(false),
      readFile: jest.fn(),
      shouldIgnore: jest.fn().mockReturnValue(false)
    };

    indexer = new CodebaseIndexer(process.cwd(), mockFileSystemManager);
  });

  describe('constructor', () => {
    it('should initialize with default values', () => {
      expect(indexer.rootPath).toBeDefined();
      expect(indexer.index).toBeInstanceOf(Map);
      expect(indexer.languages).toBeInstanceOf(Set);
      expect(indexer.frameworks).toEqual([]);
      expect(indexer.dependencies).toBeInstanceOf(Map);
      expect(indexer.lastIndexed).toBeNull();
    });
  });

  describe('_detectLanguage', () => {
    it('should detect JavaScript files', () => {
      expect(indexer._detectLanguage('test.js')).toBe('JavaScript');
      expect(indexer._detectLanguage('test.jsx')).toBe('JavaScript');
    });

    it('should detect TypeScript files', () => {
      expect(indexer._detectLanguage('test.ts')).toBe('TypeScript');
      expect(indexer._detectLanguage('test.tsx')).toBe('TypeScript');
    });

    it('should detect Python files', () => {
      expect(indexer._detectLanguage('test.py')).toBe('Python');
    });

    it('should detect HTML files', () => {
      expect(indexer._detectLanguage('index.html')).toBe('HTML');
      expect(indexer._detectLanguage('page.htm')).toBe('HTML');
    });

    it('should detect CSS files', () => {
      expect(indexer._detectLanguage('style.css')).toBe('CSS');
      expect(indexer._detectLanguage('style.scss')).toBe('SCSS');
    });

    it('should return null for unknown extensions', () => {
      expect(indexer._detectLanguage('test.unknown')).toBeNull();
    });
  });

  describe('detectLanguages', () => {
    it('should return array of detected languages', () => {
      indexer.languages.add('JavaScript');
      indexer.languages.add('TypeScript');
      
      const languages = indexer.detectLanguages();
      expect(languages).toContain('JavaScript');
      expect(languages).toContain('TypeScript');
      expect(languages.length).toBe(2);
    });

    it('should return empty array when no languages detected', () => {
      const languages = indexer.detectLanguages();
      expect(languages).toEqual([]);
    });
  });

  describe('detectFrameworks', () => {
    it('should detect React framework', async () => {
      mockFileSystemManager.readFile.mockResolvedValue(
        JSON.stringify({
          dependencies: { react: '^18.0.0', 'react-dom': '^18.0.0' }
        })
      );
      indexer.index.set('package.json', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toContain('React');
    });

    it('should detect Vue framework', async () => {
      mockFileSystemManager.readFile.mockResolvedValue(
        JSON.stringify({
          dependencies: { vue: '^3.0.0' }
        })
      );
      indexer.index.set('package.json', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toContain('Vue');
    });

    it('should detect Express framework', async () => {
      mockFileSystemManager.readFile.mockResolvedValue(
        JSON.stringify({
          dependencies: { express: '^4.18.0' }
        })
      );
      indexer.index.set('package.json', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toContain('Express');
    });

    it('should detect Next.js framework', async () => {
      mockFileSystemManager.readFile.mockResolvedValue(
        JSON.stringify({
          dependencies: { next: '^13.0.0' }
        })
      );
      indexer.index.set('package.json', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toContain('Next.js');
    });

    it('should detect Django framework from requirements.txt', async () => {
      mockFileSystemManager.readFile.mockResolvedValue('django>=4.0.0\nrequests>=2.28.0');
      indexer.index.set('requirements.txt', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toContain('Django');
    });

    it('should detect Flask framework from requirements.txt', async () => {
      mockFileSystemManager.readFile.mockResolvedValue('flask>=2.0.0');
      indexer.index.set('requirements.txt', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toContain('Flask');
    });

    it('should handle errors gracefully', async () => {
      mockFileSystemManager.readFile.mockRejectedValue(new Error('Read error'));
      indexer.index.set('package.json', {});

      const frameworks = await indexer.detectFrameworks();
      expect(frameworks).toEqual([]);
    });
  });

  describe('findDependencies', () => {
    it('should parse dependencies from package.json', async () => {
      mockFileSystemManager.readFile.mockResolvedValue(
        JSON.stringify({
          dependencies: {
            react: '^18.0.0',
            express: '^4.18.0'
          },
          devDependencies: {
            jest: '^29.0.0'
          }
        })
      );
      indexer.index.set('package.json', {});

      const deps = await indexer.findDependencies();
      expect(deps.get('react')).toBe('^18.0.0');
      expect(deps.get('express')).toBe('^4.18.0');
      expect(deps.get('jest')).toBe('^29.0.0');
      expect(deps.size).toBe(3);
    });

    it('should parse dependencies from requirements.txt', async () => {
      mockFileSystemManager.readFile.mockResolvedValue(
        'django>=4.0.0\nrequests==2.28.0\nflask~=2.0.0\n# comment\npytest'
      );
      indexer.index.set('requirements.txt', {});

      const deps = await indexer.findDependencies();
      expect(deps.get('django')).toBe('>=4.0.0');
      expect(deps.get('requests')).toBe('==2.28.0');
      expect(deps.get('flask')).toBe('~=2.0.0');
      expect(deps.get('pytest')).toBe('*');
    });

    it('should handle missing dependency files', async () => {
      const deps = await indexer.findDependencies();
      expect(deps.size).toBe(0);
    });

    it('should handle read errors gracefully', async () => {
      mockFileSystemManager.readFile.mockRejectedValue(new Error('Read error'));
      indexer.index.set('package.json', {});

      const deps = await indexer.findDependencies();
      expect(deps.size).toBe(0);
    });
  });

  describe('getProjectStructure', () => {
    it('should return project structure summary', () => {
      indexer.index.set('file1.js', { language: 'JavaScript' });
      indexer.index.set('file2.ts', { language: 'TypeScript' });
      indexer.languages.add('JavaScript');
      indexer.languages.add('TypeScript');
      indexer.frameworks = ['React', 'Express'];
      indexer.dependencies.set('react', '^18.0.0');
      indexer.lastIndexed = new Date('2024-01-01');

      const structure = indexer.getProjectStructure();
      expect(structure.totalFiles).toBe(2);
      expect(structure.languages).toContain('JavaScript');
      expect(structure.languages).toContain('TypeScript');
      expect(structure.frameworks).toContain('React');
      expect(structure.frameworks).toContain('Express');
      expect(structure.dependencies.react).toBe('^18.0.0');
      expect(structure.lastIndexed).toEqual(new Date('2024-01-01'));
    });
  });

  describe('getFileMetadata', () => {
    it('should return metadata for existing file', async () => {
      const metadata = { path: 'test.js', language: 'JavaScript' };
      indexer.index.set('test.js', metadata);

      const result = await indexer.getFileMetadata('test.js');
      expect(result).toEqual(metadata);
    });

    it('should return null for non-existent file', async () => {
      const result = await indexer.getFileMetadata('nonexistent.js');
      expect(result).toBeNull();
    });
  });

  describe('getFilesByLanguage', () => {
    it('should return files of specified language', () => {
      indexer.index.set('file1.js', { path: 'file1.js', language: 'JavaScript' });
      indexer.index.set('file2.js', { path: 'file2.js', language: 'JavaScript' });
      indexer.index.set('file3.py', { path: 'file3.py', language: 'Python' });

      const jsFiles = indexer.getFilesByLanguage('JavaScript');
      expect(jsFiles.length).toBe(2);
      expect(jsFiles[0].language).toBe('JavaScript');
      expect(jsFiles[1].language).toBe('JavaScript');
    });

    it('should return empty array for language with no files', () => {
      const files = indexer.getFilesByLanguage('Ruby');
      expect(files).toEqual([]);
    });
  });

  describe('getIndex', () => {
    it('should return the complete index', () => {
      indexer.index.set('file1.js', { language: 'JavaScript' });
      indexer.index.set('file2.py', { language: 'Python' });

      const index = indexer.getIndex();
      expect(index).toBeInstanceOf(Map);
      expect(index.size).toBe(2);
      expect(index.has('file1.js')).toBe(true);
      expect(index.has('file2.py')).toBe(true);
    });
  });

  describe('updateIndex', () => {
    beforeEach(() => {
      mockFileSystemManager.exists = jest.fn();
      mockFileSystemManager.getStats = jest.fn();
    });

    it('should add new files to index', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 1000,
        isDirectory: false,
        modified: new Date()
      });

      const result = await indexer.updateIndex(['newfile.js']);
      expect(result.added).toBe(1);
      expect(result.updated).toBe(0);
      expect(result.removed).toBe(0);
      expect(indexer.index.has('newfile.js')).toBe(true);
    });

    it('should update existing files in index', async () => {
      indexer.index.set('existing.js', { language: 'JavaScript', size: 500 });
      
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 1000,
        isDirectory: false,
        modified: new Date()
      });

      const result = await indexer.updateIndex(['existing.js']);
      expect(result.added).toBe(0);
      expect(result.updated).toBe(1);
      expect(result.removed).toBe(0);
      expect(indexer.index.get('existing.js').size).toBe(1000);
    });

    it('should remove deleted files from index', async () => {
      indexer.index.set('deleted.js', { language: 'JavaScript' });
      mockFileSystemManager.exists.mockResolvedValue(false);

      const result = await indexer.updateIndex(['deleted.js']);
      expect(result.added).toBe(0);
      expect(result.updated).toBe(0);
      expect(result.removed).toBe(1);
      expect(indexer.index.has('deleted.js')).toBe(false);
    });

    it('should skip binary files', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 1000,
        isDirectory: false,
        modified: new Date()
      });
      mockFileSystemManager.isBinary.mockResolvedValue(true);

      const result = await indexer.updateIndex(['binary.bin']);
      expect(result.added).toBe(0);
      expect(indexer.index.has('binary.bin')).toBe(false);
    });

    it('should skip directories', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 0,
        isDirectory: true,
        modified: new Date()
      });

      const result = await indexer.updateIndex(['somedir']);
      expect(result.added).toBe(0);
      expect(indexer.index.has('somedir')).toBe(false);
    });

    it('should handle multiple files', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 1000,
        isDirectory: false,
        modified: new Date()
      });

      const result = await indexer.updateIndex(['file1.js', 'file2.py', 'file3.ts']);
      expect(result.added).toBe(3);
      expect(indexer.index.size).toBe(3);
    });
  });

  describe('startWatching and stopWatching', () => {
    afterEach(async () => {
      // Clean up any watchers after each test
      if (indexer.isCurrentlyWatching()) {
        await indexer.stopWatching();
      }
    });

    it('should start watching for file changes', async () => {
      indexer.startWatching();
      expect(indexer.isCurrentlyWatching()).toBe(true);
      expect(indexer.watcher).toBeDefined();
      await indexer.stopWatching();
    });

    it('should not start watching if already watching', async () => {
      indexer.startWatching();
      const firstWatcher = indexer.watcher;
      indexer.startWatching();
      expect(indexer.watcher).toBe(firstWatcher);
      await indexer.stopWatching();
    });

    it('should stop watching', async () => {
      indexer.startWatching();
      await indexer.stopWatching();
      expect(indexer.isCurrentlyWatching()).toBe(false);
      expect(indexer.watcher).toBeNull();
    });
  });

  describe('getMemoryUsage', () => {
    it('should calculate memory usage statistics', () => {
      indexer.index.set('file1.js', { language: 'JavaScript' });
      indexer.index.set('file2.py', { language: 'Python' });
      indexer.languages.add('JavaScript');
      indexer.languages.add('Python');
      indexer.dependencies.set('react', '^18.0.0');
      indexer.frameworks = ['React', 'Express'];

      const usage = indexer.getMemoryUsage();
      expect(usage.indexedFiles).toBe(2);
      expect(usage.languages).toBe(2);
      expect(usage.dependencies).toBe(1);
      expect(usage.frameworks).toBe(2);
      expect(usage.estimatedMemoryBytes).toBeGreaterThan(0);
      expect(usage.estimatedMemoryMB).toBeDefined();
    });
  });

  describe('clearIndex', () => {
    it('should clear all index data', () => {
      indexer.index.set('file1.js', { language: 'JavaScript' });
      indexer.languages.add('JavaScript');
      indexer.frameworks = ['React'];
      indexer.dependencies.set('react', '^18.0.0');
      indexer.lastIndexed = new Date();

      indexer.clearIndex();

      expect(indexer.index.size).toBe(0);
      expect(indexer.languages.size).toBe(0);
      expect(indexer.frameworks.length).toBe(0);
      expect(indexer.dependencies.size).toBe(0);
      expect(indexer.lastIndexed).toBeNull();
    });
  });
});
